INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '80d538ad-0323-4071-a2e7-30e4d6ba2d8f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Astro File Routing as Architecture — Colocating Data, Errors, and Navigation State at the Route Level$escape$,
  $escape$Astro's `src/pages/` directory isn't just routing — it's your architecture boundary. Each `.astro` file owns its full request lifecycle: the `---` frontmatter block is your loader, executing server-side before any markup renders. Unlike Next.js route segments, Astro colocates data fetching, redirects, and auth guards in a single file with no extra conventions to learn.

For dynamic routes, `getStaticPaths()` returns the param matrix at build time; flip `export const prerender = false` per-route for SSR without touching anything else. Error handling at the route level means returning `Astro.redirect('/404')` from the frontmatter block, or placing `404.astro` directly in `src/pages/` for unmatched paths — no special export required.

Colocate route-private components using the `_` underscore prefix: `src/pages/blog/_PostCard.astro` stays adjacent to its consumer but never becomes a URL. For client-navigation loading states, `<ViewTransitions />` in your layout head activates `transition:animate` directives per element, giving each route declarative enter/exit control without a separate loading file. The page IS the vertical slice.$escape$,
  $escape$---
// src/pages/blog/[slug].astro
import { getCollection, getEntry } from 'astro:content';

export async function getStaticPaths() {
  const posts = await getCollection('blog');
  return posts.map(post => ({ params: { slug: post.slug } }));
}

const { slug } = Astro.params;
const post = await getEntry('blog', slug!);

if (!post) return Astro.redirect('/404');

const { Content } = await post.render();
---
<article transition:animate="slide">
  <h1>{post.data.title}</h1>
  <Content />
</article>$escape$,
  $escape$typescript$escape$,
