INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd09fe9d7-f8b3-4ef8-a91e-bd4010e42d44',
  '00000000-0000-0000-0000-000000000001',
  $escape$Astro Islands — Push client: Directives to the Leaves, Not the Roots$escape$,
  $escape$Every Astro component is server-rendered by default — zero JS shipped. Hydration only begins when you attach a `client:*` directive to a framework component. The critical mistake is attaching that directive too high in the tree. If you slap `client:load` on a `<ProductPage />` React component because one nested button needs a click handler, you've hydrated the entire subtree: images, static headings, price text — all now part of a JS bundle. Astro's island architecture is designed to prevent exactly this. The fix: decompose. Keep `ProductPage.astro` as a static `.astro` file, pull the interactive piece into its own component — `<AddToCartButton client:load />` — and drop only that into the page. The rest renders at build time, ships no JS, and costs nothing at runtime. Use `client:visible` for below-the-fold islands to further defer hydration. The rule: an island's boundary should be the smallest interactive unit, never a layout container. Measure with `astro build && astro preview` — check page weight in DevTools before and after splitting.$escape$,
  $escape$---
// src/pages/product/[id].astro
import ProductDetails from '../components/ProductDetails.astro';
import AddToCartButton from '../components/AddToCartButton.tsx';

const { product } = Astro.props;
---

<!-- Static island: zero JS -->
<ProductDetails product={product} />

<!-- Hydrated leaf only: ~2 KB JS -->
<AddToCartButton productId={product.id} client:load />

<!-- Below fold: deferred until visible -->
<ReviewSection productId={product.id} client:visible />$escape$,
