INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0bb6705b-0252-482f-9df7-a1eff2b7b9df',
  '00000000-0000-0000-0000-000000000001',
  $escape$Astro Rendering Modes — SSG vs SSR vs ISR Decision Matrix and Parallel Frontmatter Fetching$escape$,
  $escape$Astro's rendering modes map directly to data freshness requirements. Use SSG (`export const prerender = true`, the default) for documentation, blog posts, and marketing pages — data baked at build time, zero runtime cost, peak Lighthouse scores. Flip to SSR (`prerender = false` with `output: 'server'` in `astro.config.mjs`) for auth-gated routes, personalized dashboards, or any page that reads `Astro.locals` or `Astro.cookies`. For content that's mostly static but needs periodic refresh, pair a Vercel or Netlify adapter with `export const revalidate = 60` for ISR semantics without a full rebuild.

The critical mistake on SSR pages is sequential `await`s in frontmatter — each one suspends the entire render. Fan out with `Promise.all()` instead; Astro's frontmatter is async-first so parallel resolution is native. `getCollection()` and `getEntry()` are cached in-process, but every external API call must be parallelized manually.

Decision rule: if `Astro.locals` or `Astro.cookies` are touched → SSR. If data changes faster than your deploy cadence → ISR/revalidate. Otherwise → SSG.$escape$,
  $escape$---
// pages/dashboard.astro — SSR page with parallel data fetching
export const prerender = false;

import { getUser, getFeed, getNotifications } from "@/lib/api";

// Bad: sequential = ~900ms (300ms × 3)
// const user = await getUser(Astro.locals.userId);
// const feed = await getFeed(user.id);

// Good: parallel = ~300ms
const [user, feed, notifications] = await Promise.all([
  getUser(Astro.locals.userId),
  getFeed(Astro.locals.userId),
  getNotifications(Astro.locals.userId),
]);
---$escape$,
