INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '558d26f2-b43d-4c84-8038-3d45cf72253b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Astro Actions — Forms That Work Without JavaScript$escape$,
  $escape$Astro Actions (stable since 4.9) wire server logic directly to HTML forms with Zod validation running at the server boundary before your handler is called. Define actions in `src/actions/index.ts` using `defineAction` with an `input` schema from `astro:schema` — invalid submissions never reach the handler; Astro returns a typed `ActionError` automatically. Set `accept: 'form'` to parse `multipart/form-data` or `application/x-www-form-urlencoded` natively. Bind the action via `action={actions.contact}` on any `<form method="POST">` — Astro serializes the RPC endpoint URL. Progressive enhancement is built-in: no JS means a full-page POST round-trip, add a client `enhance` hook for fetch-based submission without duplicating logic. Read results in the same page's frontmatter with `Astro.getActionResult(actions.contact)`, which returns `{ data, error }` after a POST and `undefined` on GET. Validation errors are fully typed — `result.error.fields.email` exposes Zod messages per field, no manual `try/catch` at the boundary required.$escape$,
  $escape$// src/actions/index.ts
import { defineAction } from 'astro:actions';
import { z } from 'astro:schema';

export const server = {
  contact: defineAction({
    accept: 'form',
    input: z.object({
      email: z.string().email(),
      message: z.string().min(10),
    }),
    handler: async ({ email, message }) => {
      await sendEmail({ email, message });
      return { sent: true };
    },
  }),
};$escape$,
  $escape$typescript$escape$,
