INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '23b2209f-08d8-4d71-89ec-5714f665823a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Astro Route Conventions — Segment Naming and Action Consistency at Scale$escape$,
  $escape$Astro's file router silently enforces naming contracts. A `[slug].astro` page requires `getStaticPaths()` to return `params: { slug }` — a mismatch causes a cryptic build error. Use semantic segment names tied to content type: `[slug]` for human-readable identifiers, `[id]` for UUIDs, `[...path]` for nested catch-alls. Prefix non-route files with `_` (`_queries.ts`, `_utils.ts`) so Astro excludes them from routing without moving them out of `src/pages/`.

For API endpoints, always export named HTTP verbs (`GET`, `POST`) — Astro ignores default exports on `.ts` endpoint files. With Astro Actions (v4+), split handlers into namespaced files under `src/actions/` and compose them in `index.ts` through a single `server` export. Name every action with a verb-noun pair: `createPost`, `deleteComment`, `publishDraft`. This makes call sites like `actions.blog.createPost()` self-documenting across any component or page. Mixing imperative (`handle`, `submit`) and noun-only (`post`, `comment`) naming in the same actions layer is the fastest path to an unmaintainable server boundary.$escape$,
  $escape$// src/actions/blog.ts
import { defineAction } from 'astro:actions';
import { z } from 'astro:schema';

export const blog = {
  createPost: defineAction({
    input: z.object({ title: z.string(), slug: z.string() }),
    handler: async ({ title, slug }, ctx) => {
      return db.posts.create({ title, slug, authorId: ctx.locals.user.id });
    },
  }),
  deletePost: defineAction({
    input: z.object({ id: z.string() }),
    handler: async ({ id }) => db.posts.delete(id),
  }),
};

// src/actions/index.ts
import { blog } from './blog';
export const server = { blog };$escape$,
  $escape$typescript$escape$,
