INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'add1639c-8105-47c2-bc58-39ed42ef05a6',
  '00000000-0000-0000-0000-000000000001',
  $escape$Astro Environment Variables — PUBLIC_ Prefix, Private Secrets, and astro:env Validation$escape$,
  $escape$Astro exposes variables to the client bundle only when prefixed with `PUBLIC_`. Anything without that prefix is server-only — never inlined into the client. This is Astro's equivalent of Next.js's `NEXT_PUBLIC_` convention, but enforced differently.

The modern way to handle this is `astro:env`, introduced in Astro 5. Define a schema in `astro.config.mjs` using `envField`. Astro validates every declared variable at startup — missing or maltyped secrets throw immediately, not at runtime when a user triggers the affected path.

Import server secrets from `astro:env/server` and public vars from `astro:env/client`. Attempting to import a `context: "server"` variable inside a `.astro` component's client-side `<script>` tag is a type error. The module boundary enforces what the prefix convention only suggests.

Never rely on `import.meta.env` directly for secrets in production code — it skips validation. Always go through the typed `astro:env` imports so TypeScript and the Astro build pipeline can catch exposure mistakes at compile time rather than in a breach postmortem.$escape$,
  $escape$// astro.config.mjs
import { defineConfig, envField } from "astro/config";

export default defineConfig({
  env: {
    schema: {
      PUBLIC_SITE_URL: envField.string({ context: "client", access: "public" }),
      DATABASE_URL:    envField.string({ context: "server", access: "secret" }),
      GROQ_API_KEY:    envField.string({ context: "server", access: "secret" }),
    },
  },
});

// src/pages/api/query.ts
import { DATABASE_URL, GROQ_API_KEY } from "astro:env/server";
// import { DATABASE_URL } from "astro:env/client"; // ← compile error$escape$,
  $escape$typescript$escape$,
