INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '646a929a-7a62-4727-b34a-7cc54efbdb52',
  '00000000-0000-0000-0000-000000000001',
  $escape$Astro API Layer — Route Handlers, Server Actions, and Auth Middleware Done Right$escape$,
  $escape$Astro gives you three distinct primitives for your API layer — each with a clear job. Route handlers in `src/pages/api/` export named HTTP verbs (`GET`, `POST`) and are ideal for public endpoints consumed by third parties or client-side `fetch`. They receive a typed `APIContext` with `request`, `params`, and `locals`. Server Actions (`defineAction` in `src/actions/index.ts`) are for mutations triggered from your own UI — they're type-safe, support Zod input validation out of the box, and are called with `actions.foo()` from any component. Middleware in `src/middleware.ts` uses `defineMiddleware` (or `sequence()` for composing multiple guards) to run before every request. Set `context.locals.user` here after verifying a Clerk or JWT session — both route handlers and Server Actions inherit `locals` from the same `APIContext`, so auth logic stays in one place. Never duplicate auth checks inside individual actions; push the boundary to middleware and trust `locals` downstream.$escape$,
  $escape$// src/middleware.ts
import { defineMiddleware, sequence } from 'astro:middleware';
import { verifyToken } from './lib/auth';

const authMiddleware = defineMiddleware(async (ctx, next) => {
  const token = ctx.cookies.get('session')?.value;
  ctx.locals.user = token ? await verifyToken(token) : null;
  return next();
});

export const onRequest = sequence(authMiddleware);

// src/actions/index.ts
import { defineAction } from 'astro:actions';
import { z } from 'astro:schema';

export const server = {
  createPost: defineAction({
    input: z.object({ title: z.string().min(1), body: z.string() }),
    handler: async (input, ctx) => {
      if (!ctx.locals.user) throw new ActionError({ code: 'UNAUTHORIZED' });
      return db.posts.create({ ...input, authorId: ctx.locals.user.id });
    },
  }),
};$escape$,
