INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '921619ab-1197-43ba-a98f-00f9ef2f8e77',
  '00000000-0000-0000-0000-000000000001',
  $escape$Astro Bundle Optimization — Code Splitting, Dynamic Imports, and Bundle Analysis$escape$,
  $escape$Astro ships zero JavaScript by default, and its Islands Architecture ensures each `client:*` directive generates an isolated chunk scoped to that component alone — not the whole page. Route-level splitting is automatic: `dist/_astro/` contains per-route JS bundles loaded only on the matching page, with no manual configuration required.

For heavy components, use dynamic imports inside `.astro` frontmatter to defer parsing until runtime:

```astro
const { default: Chart } = await import('../components/Chart.tsx');
```

Pair this with `client:visible` to delay hydration until the element enters the viewport, cutting both network transfer and parse cost on initial load.

To audit what ships, add `rollup-plugin-visualizer` to your Vite config — Astro's build pipeline is Vite under the hood. After `astro build`, open `dist/stats.html` for a treemap of every chunk.

Use `manualChunks` in `vite.build.rollupOptions` to pin heavy shared deps like `recharts` or `three` into named vendor chunks. Without this, Astro may duplicate them across multiple island bundles that share the same dependency, bloating total transfer size.$escape$,
  $escape$// astro.config.mjs
import { defineConfig } from 'astro/config';
import { visualizer } from 'rollup-plugin-visualizer';

export default defineConfig({
  vite: {
    plugins: [
      visualizer({ open: true, filename: 'dist/stats.html' })
    ],
    build: {
      rollupOptions: {
        output: {
          manualChunks: {
            'vendor-charts': ['recharts'],
            'vendor-3d': ['three'],
          }
        }
      }
    }
  }
});$escape$,
  $escape$javascript$escape$,
