INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ae0a978f-6b69-43ec-b23d-cbd8dec58418',
  '00000000-0000-0000-0000-000000000001',
  $escape$Astro Production Monitoring — Edge Logs, Sentry SSR, and Web Vitals from RUM$escape$,
  $escape$Astro's `@sentry/astro` integration auto-instruments SSR routes and API endpoints — add it via `integrations: [sentry({ dsn, tracesSampleRate })]` in `astro.config.mjs` and source maps upload on every build automatically. No manual `Sentry.init()` needed in server code.

For edge function logs, define `src/middleware.ts` using `defineMiddleware` from `astro:middleware`. The middleware runs per-request at the edge (Vercel/Cloudflare adapters), giving you structured timing and request ID propagation via `ctx.locals`. Attach `ctx.locals.requestId` and call `Sentry.setTag` inside the same scope to correlate edge logs with Sentry traces end-to-end.

Web Vitals need a client island. Import `onCLS`, `onLCP`, `onINP` from `web-vitals` inside a `client:load` component and flush to your RUM endpoint. If `<ViewTransitions />` is enabled, re-register on `document.addEventListener('astro:page-load', registerVitals)` — without this, SPA-style navigations silently skip LCP re-sampling. Use `astro:after-swap` if you need to reset state before the new page renders.$escape$,
  $escape$// src/middleware.ts
import { defineMiddleware } from 'astro:middleware';
import * as Sentry from '@sentry/astro';

export const onRequest = defineMiddleware(async (ctx, next) => {
  const reqId = crypto.randomUUID();
  ctx.locals.requestId = reqId;

  return Sentry.withIsolationScope(async (scope) => {
    scope.setTag('requestId', reqId);
    scope.setTag('route', ctx.routePattern);
    const start = performance.now();
    const res = await next();
    console.log(JSON.stringify({
      method: ctx.request.method,
      path: ctx.url.pathname,
      status: res.status,
      ms: Math.round(performance.now() - start),
      reqId,
    }));
    return res;
  });
});$escape$,
