INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '037e4d0b-8147-40b9-82b4-cfeb4bd8984e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Astro Middleware — Edge Guards, A/B Tests, and Geo Routing Before the Page Renders$escape$,
  $escape$Astro middleware lives in `src/middleware.ts` and runs on every request before any page or endpoint renders — or at the edge if your adapter supports it (Vercel, Cloudflare). Use `defineMiddleware` to intercept `context` and `next`. Attach anything to `context.locals` and it flows directly into `Astro.locals` inside `.astro` files and API routes — no prop drilling.

For auth guards, read a session cookie via `context.cookies.get()` and call `context.redirect('/login')` before `next()`. For A/B testing, assign a variant to a cookie on first visit and store it in `locals.variant` so the page renders the right branch server-side — no layout shift. For geolocation, Cloudflare injects `cf-ipcountry` headers you can read off `context.request.headers` to serve region-locked content. Rate limiting works the same way: check a KV store or Upstash Redis in middleware, return a `new Response('Too Many Requests', { status: 429 })` directly — bypassing `next()` entirely. Chain independent concerns with Astro's `sequence()` helper to keep each middleware focused and composable.$escape$,
  $escape$// src/middleware.ts
import { defineMiddleware, sequence } from 'astro:middleware';

const auth = defineMiddleware(async (ctx, next) => {
  const session = ctx.cookies.get('session')?.value;
  if (!session && ctx.url.pathname.startsWith('/dashboard')) {
    return ctx.redirect('/login');
  }
  ctx.locals.userId = session ?? null;
  return next();
});

const geo = defineMiddleware(async (ctx, next) => {
  const country = ctx.request.headers.get('cf-ipcountry') ?? 'US';
  ctx.locals.country = country;
  return next();
});

export const onRequest = sequence(auth, geo);$escape$,
  $escape$typescript$escape$,
